    if (saveundo) {
      this.changes.PushChange('addsheet');
      this.changes.AddDo('workbook addsheet ' + SocialCalc.encodeForSave(trimmed));
      this.changes.AddUndo('workbook deletesheet ' + SocialCalc.encodeForSave(trimmed));
    }
