    if (saveundo) {
      this.changes.AddDo(
        'workbook renamesheet ' +
          SocialCalc.encodeForSave(originalName) +
          ' ' +
          SocialCalc.encodeForSave(trimmedNew),
      );
      this.changes.AddUndo(
        'workbook renamesheet ' +
          SocialCalc.encodeForSave(trimmedNew) +
          ' ' +
          SocialCalc.encodeForSave(originalName),
      );
    }
