  WorkbookRoot.ExecuteWorkbookCommand = function (workbook, cmd, saveundo) {
    const parts = cmd.split(' ');
    const what = parts[1];
    switch (what) {
      case 'addsheet':
        workbook.AddSheet(SocialCalc.decodeFromSave(parts.slice(2).join(' ')), null, saveundo);
        break;
      case 'deletesheet':
        workbook.DeleteSheet(SocialCalc.decodeFromSave(parts.slice(2).join(' ')), saveundo);
        break;
      case 'renamesheet': {
        const oldName = SocialCalc.decodeFromSave(parts[2]);
        const newName = SocialCalc.decodeFromSave(parts.slice(3).join(' '));
        workbook.RenameSheet(oldName, newName, saveundo);
        break;
      }
      case 'reordersheet': {
        const name = SocialCalc.decodeFromSave(parts[2]);
        const index = Number(parts[3]);
        workbook.ReorderSheet(name, index, saveundo);
        break;
      }
      case 'hidesheet':
        workbook.HideSheet(SocialCalc.decodeFromSave(parts.slice(2).join(' ')), saveundo);
        break;
      case 'unhidesheet':
        workbook.UnhideSheet(SocialCalc.decodeFromSave(parts.slice(2).join(' ')), saveundo);
        break;
      case 'setactivesheet':
        workbook.SetActiveSheet(SocialCalc.decodeFromSave(parts.slice(2).join(' ')), saveundo);
        break;
      case 'restoreformula': {
        const sname = SocialCalc.decodeFromSave(parts[2]);
        const coord = parts[3];
        const formula = SocialCalc.decodeFromSave(parts.slice(4).join(' '));
        const sheet = workbook.GetSheet(sname);
        if (sheet) {
          const cell = sheet.GetAssuredCell(coord);
          cell.formula = formula;
          cell.datatype = 'f';
          delete cell.parseinfo;
        }
        break;
      }
      case 'restoresheet': {
        const name = SocialCalc.decodeFromSave(parts[2]);
        const index = Number(parts[3]);
        const visible = parts[4] === 'yes';
        const editorSettings = SocialCalc.decodeFromSave(parts[5]);
        const savedText = SocialCalc.decodeFromSave(parts.slice(6).join(' '));
        const restored = new SocialCalc.Sheet();
        restored.ParseSheetSave(savedText);
        workbook.AddSheet(name, restored, false);
        workbook.ReorderSheet(name, index, false);
        const entry = wbEntry(workbook, SocialCalc.WorkbookNormalizeSheetName(name));
        entry.visible = visible;
        entry.editorSettings = editorSettings;
        break;
      }
      default:
        break;
    }
  };
  WorkbookRoot.Workbook.prototype.WorkbookUndo = function () {
    const tos = this.changes.TOS();
    if (!tos) return;
    for (let i = tos.undo.length - 1; i >= 0; i--) {
      SocialCalc.ExecuteWorkbookCommand(this, tos.undo[i], false);
    }
    this.changes.Undo();
  };
  WorkbookRoot.Workbook.prototype.WorkbookRedo = function () {
    if (!this.changes.Redo()) return;
    const tos = this.changes.TOS();
    for (let i = 0; i < tos.command.length; i++) {
      SocialCalc.ExecuteWorkbookCommand(this, tos.command[i], false);
    }
  };
  function wbRecalcAll(workbook, callback) {
    const names = workbook.sheetOrder.slice();
    if (names.length === 0) {
      if (callback) callback();
      return;
    }
    const maxRounds = names.length;
    function runRound(roundsLeft) {
      let idx = 0;
      let roundChanged = false;
      function attachOnce(sheet) {
        const prevcb = sheet.statuscallback;
        const prevparams = sheet.statuscallbackparams;
        sheet.statuscallback = function (data, status, arg, _params) {
          if (prevcb) prevcb(data, status, arg, prevparams);
          if (status === 'calcfinished') {
            sheet.statuscallback = prevcb;
            sheet.statuscallbackparams = prevparams;
            if (sheet.recalcchangedavalue) roundChanged = true;
            onOneDone();
          }
        };
      }
      function startSheet(i) {
        const sheet = workbook.GetSheet(names[i]);
        if (!sheet) {
          idx = i + 1;
          onOneDone();
          return;
        }
        sheet.recalcchangedavalue = false;
        attachOnce(sheet);
        sheet.RecalcSheet();
      }
      function onOneDone() {
        idx++;
        if (idx < names.length) {
          startSheet(idx);
        } else if (roundChanged && roundsLeft > 1) {
          runRound(roundsLeft - 1);
        } else {
          wbStatus(workbook, 'recalcallfinished', null);
          if (callback) callback();
        }
      }
      startSheet(0);
    }
    runRound(maxRounds);
  }
  WorkbookRoot.Workbook.prototype.RecalcAll = function (callback) {
    wbRecalcAll(this, callback);
  };
  const WORKBOOK_SAVE_BOUNDARY = 'SocialCalcWorkbookSave';
  WorkbookRoot.CreateWorkbookSave = function (workbook) {
    const enc = SocialCalc.encodeForSave;
    const lines = ['# SocialCalc Workbook Save', 'version:1.0'];
    if (workbook.activeSheetName != null) {
      lines.push('active:' + enc(workbook.activeSheetName));
    }
    const names = workbook.sheetOrder;
    for (const name of names) {
      const entry = workbook.sheets[SocialCalc.WorkbookNormalizeSheetName(name)];
      lines.push('sheet:' + enc(entry.name) + ':visible:' + (entry.visible ? 'yes' : 'no'));
    }
    for (const name of names) {
      const entry = workbook.sheets[SocialCalc.WorkbookNormalizeSheetName(name)];
      if (entry.editorSettings) {
        lines.push('editorsettings:' + enc(entry.name) + ':' + enc(entry.editorSettings));
      }
    }
    lines.push('');
    let result =
      'socialcalc:workbook:version:1.0\n' +
      'MIME-Version: 1.0\nContent-Type: multipart/mixed; boundary=' +
      WORKBOOK_SAVE_BOUNDARY +
      '\n' +
      '--' +
      WORKBOOK_SAVE_BOUNDARY +
      '\nContent-type: text/plain; charset=UTF-8\n\n' +
      lines.join('\n');
    for (const name of names) {
      const entry = workbook.sheets[SocialCalc.WorkbookNormalizeSheetName(name)];
      result +=
        '--' +
        WORKBOOK_SAVE_BOUNDARY +
        '\nContent-type: text/plain; charset=UTF-8\n\n' +
        entry.sheet.CreateSheetSave();
    }
    result += '--' + WORKBOOK_SAVE_BOUNDARY + '--\n';
    return result;
  };
  WorkbookRoot.DecodeWorkbookSave = function (str) {
    const dec = SocialCalc.decodeFromSave;
    const pos1 = str.search(/^MIME-Version:\s1\.0/im);
    if (pos1 < 0) return null;
    const mpregex = /^Content-Type:\s*multipart\/mixed;\s*boundary=(\S+)/gim;
    mpregex.lastIndex = pos1;
    const mpmatch = mpregex.exec(str);
    if (!mpmatch || mpregex.lastIndex <= 0) return null;
    const boundary = mpmatch[1];
    const boundaryregex = new RegExp('^--' + boundary + '(?:\r\n|\n)', 'mg');
    boundaryregex.lastIndex = mpregex.lastIndex;
    if (!boundaryregex.exec(str)) return null;
    const blanklineregex = /(?:\r\n|\n)(?:\r\n|\n)/gm;
    blanklineregex.lastIndex = boundaryregex.lastIndex;
    const blankmatch = blanklineregex.exec(str);
    if (!blankmatch) return null;
    let start = blanklineregex.lastIndex;
    boundaryregex.lastIndex = start;
    const headerEndMatch = boundaryregex.exec(str);
    if (!headerEndMatch) return null;
    let ending = headerEndMatch.index;
    const headerLines = str.substring(start, ending).split(/\r\n|\n/);
    let active = null;
    const sheets = [];
    const editorSettingsMap = {};
    for (const line of headerLines) {
      const parts = line.split(':');
      switch (parts[0]) {
        case 'active':
          active = dec(parts.slice(1).join(':'));
          break;
        case 'sheet':
          sheets.push({
            name: dec(parts[1]),
            visible: parts[3] === 'yes',
            editorSettings: '',
          });
          break;
        case 'editorsettings':
          editorSettingsMap[dec(parts[1])] = dec(parts.slice(2).join(':'));
          break;
        default:
          break;
      }
    }
    for (const entry of sheets) {
      if (Object.prototype.hasOwnProperty.call(editorSettingsMap, entry.name)) {
        entry.editorSettings = editorSettingsMap[entry.name];
      }
    }
    const sheetTexts = [];
    for (let i = 0; i < sheets.length; i++) {
      blanklineregex.lastIndex = ending;
      const partBlank = blanklineregex.exec(str);
      if (!partBlank) return null;
      start = blanklineregex.lastIndex;
      if (i === sheets.length - 1) {
        const lastregex = new RegExp('^--' + boundary + '--$', 'mg');
        lastregex.lastIndex = start;
        const lastmatch = lastregex.exec(str);
        if (!lastmatch) return null;
        ending = lastmatch.index;
      } else {
        boundaryregex.lastIndex = start;
        const nextmatch = boundaryregex.exec(str);
        if (!nextmatch) return null;
        ending = nextmatch.index;
      }
      sheetTexts.push(str.substring(start, ending));
    }
    return {
      active,
      sheets,
      sheetTexts,
    };
  };
  WorkbookRoot.LoadWorkbookSave = function (workbook, str) {
    const decoded = SocialCalc.DecodeWorkbookSave(str);
    if (!decoded || decoded.sheets.length === 0) return;
    const staged = new SocialCalc.Workbook();
    for (let i = 0; i < decoded.sheets.length; i++) {
      const meta = decoded.sheets[i];
      const sheet = new SocialCalc.Sheet();
      sheet.ParseSheetSave(decoded.sheetTexts[i]);
      const code = staged.AddSheet(meta.name, sheet, false);
      if (code !== SocialCalc.WorkbookNameValidation.OK) {
        for (const key in staged.sheets) wbCacheUnregister(key);
        return;
      }
      const entry = wbEntry(staged, SocialCalc.WorkbookNormalizeSheetName(meta.name));
      entry.visible = meta.visible;
      entry.editorSettings = meta.editorSettings;
    }
    if (
      decoded.active != null &&
      wbEntry(staged, SocialCalc.WorkbookNormalizeSheetName(decoded.active))
    ) {
      staged.activeSheetName = decoded.active;
    } else {
      const firstVisible = staged.sheetOrder.find((n) => staged.IsSheetVisible(n));
      staged.activeSheetName = firstVisible || staged.sheetOrder[0];
    }
    for (const key in workbook.sheets) wbCacheUnregister(key);
    for (const key in staged.sheets) wbCacheRegister(key, staged.sheets[key].sheet);
    workbook.sheetOrder = staged.sheetOrder;
    workbook.sheets = staged.sheets;
    workbook.activeSheetName = staged.activeSheetName;
    workbook.changes = new SocialCalc.UndoStack();
  };

  // SocialCalc data-validation engine (Excel/Sheets-style cell/range rules).
  // Shipping source. Concatenated after socialcalc-3 (needs SC.Cell/Sheet,
  // SC.DetermineValueType, SC.decodeFromSave/encodeForSave, SC.special_chars)
  // and after formula1 + formula-ref (needs SocialCalc.Formula.ParseFormulaIntoTokens
  // / evaluate_parsed_formula for formula-driven bounds/list sources/custom
  // rules, and AdjustFormulaCoords/OffsetFormulaCoords/ReplaceFormulaCoords for
  // structural-edit rewriting). Ambient declarations live in
  // socialcalc-3.d.ts (same pattern as OffsetFormulaCoords etc., since a
  // same-basename sibling .d.ts is silently shadowed by tsc when a .ts of the
  // same name exists in the directory).
  //
  // Policy semantics mirror lemma/validation.ts (RULE_LIST/NUMBER/DATE/
  // TEXT_LENGTH/CUSTOM, 8 comparison ops, allowBlank short-circuit, reject/warn
  // mode) — this file is the native shipping oracle; the lemma facade test
  // covers the pure decision core in isolation, matching eval-ops.ts's split
  // between a standalone LemmaScript module and formula1.ts's native engine.
  //
  // Wire format: cell.validation is a JSON string (SocialCalc.encodeForSave'd
  // for the ":" / "\n" save-format delimiters) so it round-trips through
  // CellToString / CellFromStringParts exactly like any other opaque cell
  // attribute (see "comment").

  const DVRoot = SocialCalc;
  DVRoot.DataValidation = {};
  const DV = DVRoot.DataValidation;
  DV.RULE_LIST = 'list';
  DV.RULE_NUMBER = 'number';
  DV.RULE_DATE = 'date';
  DV.RULE_TEXT_LENGTH = 'textLength';
  DV.RULE_CUSTOM = 'custom';
  DV.MODE_REJECT = 'reject';
  DV.MODE_WARN = 'warn';
  DV.EncodeRule = function (rule) {
    return JSON.stringify(rule);
  };
  DV.DecodeRule = function (encoded) {
    if (!encoded) return null;
    let parsed;
    try {
      parsed = JSON.parse(encoded);
    } catch {
      return null;
    }
    if (
      parsed &&
      typeof parsed === 'object' &&
      'kind' in parsed &&
      typeof parsed.kind === 'string'
    ) {
      return parsed;
    }
    return null;
  };
  DV.IsBlank = function (raw) {
    return raw === '';
  };
  DV.CompareOk = function (op, value, bound1, bound2) {
    if (op === 'between') return value >= bound1 && value <= bound2;
    if (op === 'notBetween') return value < bound1 || value > bound2;
    if (op === 'eq') return value === bound1;
    if (op === 'ne') return value !== bound1;
    if (op === 'gt') return value > bound1;
    if (op === 'lt') return value < bound1;
    if (op === 'ge') return value >= bound1;
    if (op === 'le') return value <= bound1;
    return false;
  };
  DV.ComputeOutcome = function (allowBlank, isBlankValue, checkPassed, mode) {
    if (allowBlank === true && isBlankValue === true) return 'pass';
    if (checkPassed === true) return 'pass';
    if (mode === 'warn') return 'warn';
    return 'reject';
  };
  DV.ListContainsCI = function (values, raw) {
    const needle = raw.toLowerCase();
    for (let i = 0; i < values.length; i++) {
      if (values[i].toLowerCase() === needle) return true;
    }
    return false;
  };
  DV.ResolveBound = function (sheet, spec) {
    if (spec === undefined || spec === null)
      return {
        value: 0,
        valid: false,
      };
    if (typeof spec === 'number')
      return {
        value: spec,
        valid: !isNaN(spec),
      };
    const text = spec + '';
    if (text.charAt(0) === '=') {
      try {
        const parseinfo = SocialCalc.Formula.ParseFormulaIntoTokens(text.substring(1));
        const result = SocialCalc.Formula.evaluate_parsed_formula(parseinfo, sheet, false);
        const num = Number(result.value);
        return {
          value: num,
          valid: !isNaN(num) && result.type.charAt(0) !== 'e',
        };
      } catch {
        return {
          value: 0,
          valid: false,
        };
      }
    }
    const determined = SocialCalc.DetermineValueType(text);
    const num = Number(determined.type.charAt(0) === 'n' ? determined.value : text);
    return {
      value: num,
      valid: !isNaN(num),
    };
  };
  DV.ResolveListValues = function (sheet, rule) {
    if (rule.values && rule.values.length > 0) return rule.values;
    if (!rule.sourceRange) return [];
    let rangeText =
      rule.sourceRange.charAt(0) === '=' ? rule.sourceRange.substring(1) : rule.sourceRange;
    const name = sheet.names && sheet.names[rangeText.toUpperCase()];
    if (name) {
      rangeText =
        name.definition.charAt(0) === '=' ? name.definition.substring(1) : name.definition;
    }
    const prange = SocialCalc.ParseRange(rangeText);
    const values = [];
    for (let row = prange.cr1.row; row <= prange.cr2.row; row++) {
      for (let col = prange.cr1.col; col <= prange.cr2.col; col++) {
        const coord = SocialCalc.crToCoord(col, row);
        const cell = sheet.cells[coord];
        if (cell && cell.datavalue !== '' && cell.datavalue != null) {
          values.push(cell.datavalue + '');
        }
      }
    }
    return values;
  };
  DV.ComputeCustomPass = function (sheet, rule) {
    if (!rule.formula) return true;
    try {
      const parseinfo = SocialCalc.Formula.ParseFormulaIntoTokens(rule.formula);
      const result = SocialCalc.Formula.evaluate_parsed_formula(parseinfo, sheet, false);
      if (result.type.charAt(0) === 'e') return false;
      return Number(result.value) !== 0;
    } catch {
      return false;
    }
  };
  DV.RuleCheckPassed = function (sheet, rule, raw) {
    if (rule.kind === DV.RULE_LIST) {
      return DV.ListContainsCI(DV.ResolveListValues(sheet, rule), raw);
    }
    if (rule.kind === DV.RULE_CUSTOM) {
      return DV.ComputeCustomPass(sheet, rule);
    }
    if (rule.kind === DV.RULE_TEXT_LENGTH) {
      const b1 = DV.ResolveBound(sheet, rule.bound1);
      const b2 = DV.ResolveBound(sheet, rule.bound2);
      if (!b1.valid) return false;
      return DV.CompareOk(rule.op || 'eq', raw.length, b1.value, b2.value);
    }
    const determined = SocialCalc.DetermineValueType(raw);
    if (determined.type.charAt(0) !== 'n') return false;
    const value = Number(determined.value);
    if (isNaN(value)) return false;
    const b1 = DV.ResolveBound(sheet, rule.bound1);
    const b2 = DV.ResolveBound(sheet, rule.bound2);
    if (!b1.valid) return false;
    return DV.CompareOk(rule.op || 'eq', value, b1.value, b2.value);
  };
  DV.EvaluateRule = function (sheet, rule, raw) {
    const blankValue = DV.IsBlank(raw);
    const passed = DV.RuleCheckPassed(sheet, rule, raw);
    return DV.ComputeOutcome(rule.allowBlank, blankValue, passed, rule.mode);
  };
  DV.EvaluateForCell = function (sheet, coord, raw) {
    const cell = sheet.cells[coord];
    const rule = cell ? DV.DecodeRule(cell.validation) : null;
    if (!rule)
      return {
        outcome: 'pass',
        rule: null,
      };
    return {
      outcome: DV.EvaluateRule(sheet, rule, raw),
      rule,
    };
  };
  DV.DefaultErrorMessage = function (rule) {
    if (rule.errorMessage) return rule.errorMessage;
    return (
      SocialCalc.Constants.s_dvDefaultError || 'The value entered does not meet validation rules.'
    );
  };
  function dvRewriteAllFields(rule, rewrite) {
    const next = { ...rule };
    if (next.sourceRange) {
      next.sourceRange =
        next.sourceRange.charAt(0) === '='
          ? '=' + rewrite(next.sourceRange.substring(1))
          : rewrite(next.sourceRange);
    }
    if (next.formula) next.formula = rewrite(next.formula);
    if (typeof next.bound1 === 'string' && next.bound1.charAt(0) === '=') {
      next.bound1 = '=' + rewrite(next.bound1.substring(1));
    }
    if (typeof next.bound2 === 'string' && next.bound2.charAt(0) === '=') {
      next.bound2 = '=' + rewrite(next.bound2.substring(1));
    }
    return next;
  }
  DV.AdjustRuleCoords = function (rule, col, coloffset, row, rowoffset) {
    return dvRewriteAllFields(rule, (text) =>
      SocialCalc.AdjustFormulaCoords(text, col, coloffset, row, rowoffset),
    );
  };
  DV.OffsetRuleCoords = function (rule, coloffset, rowoffset) {
    return dvRewriteAllFields(rule, (text) =>
      SocialCalc.OffsetFormulaCoords(text, coloffset, rowoffset),
    );
  };
  DV.ReplaceRuleCoords = function (rule, movedto) {
    return dvRewriteAllFields(rule, (text) => SocialCalc.ReplaceFormulaCoords(text, movedto));
  };

  // Opt this module into TypeScript strict checking via the r2scout config.
  // In-place TypeScript conversion of socialcalcpopup.js (SocialCalc global script).
  // Ambient API types live in socialcalcpopup.d.ts.
