    var editor = spreadsheet.editor;
    var wval = editor.workingvalues;
    var spreadsheet = SocialCalc.GetSpreadsheetControlObject();
    var idp = spreadsheet.idPrefix + 'link';
    ele = document.getElementById(idp + 'dialog');
