    var pos = SocialCalc.GetElementPositionWithScroll(spreadsheet.spreadsheetDiv);
    main.style.top = vp.height / 3 - pos.top + 'px';
    main.style.left = vp.width / 3 - pos.left + 'px';
    main.style.zIndex = '100';
