    var c = '';
    if (s.editor.ecell && s.editor.ecell.coord && s.sheet.cells[s.editor.ecell.coord]) {
      c = s.sheet.cells[s.editor.ecell.coord].comment || '';
    }
    document.getElementById(s.idPrefix + 'commenttext').value = c;
