  SpreadsheetControlSC.SpreadsheetControlSettingsSwitch = function (target) {
    SocialCalc.SettingControlReset();
    var s = SocialCalc.GetSpreadsheetControlObject();
    var sheettable = document.getElementById(s.idPrefix + 'sheetsettingstable');
    var celltable = document.getElementById(s.idPrefix + 'cellsettingstable');
    var sheettoolbar = document.getElementById(s.idPrefix + 'sheetsettingstoolbar');
    var celltoolbar = document.getElementById(s.idPrefix + 'cellsettingstoolbar');
    if (target == 'sheet') {
      sheettable.style.display = 'block';
      celltable.style.display = 'none';
      sheettoolbar.style.display = 'block';
      celltoolbar.style.display = 'none';
      SocialCalc.SettingsControlSetCurrentPanel(s.views.settings.values.sheetspanel);
    } else {
      sheettable.style.display = 'none';
      celltable.style.display = 'block';
      sheettoolbar.style.display = 'none';
      celltoolbar.style.display = 'block';
      SocialCalc.SettingsControlSetCurrentPanel(s.views.settings.values.cellspanel);
    }
  };
  SpreadsheetControlSC.SettingsControlSave = function (target) {
    var range, cmdstr;
    var s = SocialCalc.GetSpreadsheetControlObject();
    var sc = SocialCalc.SettingsControls;
    var panelobj = sc.CurrentPanel;
    var attribs = SocialCalc.SettingsControlUnloadPanel(panelobj);
    SocialCalc.SetTab(s.tabs[0].name);
    SocialCalc.KeyboardFocus();
    if (target == 'sheet') {
      cmdstr = s.sheet.DecodeSheetAttributes(attribs);
    } else if (target == 'cell') {
      if (s.editor.range.hasrange) {
        range =
          SocialCalc.crToCoord(s.editor.range.left, s.editor.range.top) +
          ':' +
          SocialCalc.crToCoord(s.editor.range.right, s.editor.range.bottom);
      }
      cmdstr = s.sheet.DecodeCellAttributes(s.editor.ecell.coord, attribs, range);
    } else {
    }
    if (cmdstr) {
      s.editor.EditorScheduleSheetCommands(cmdstr, true, false);
    }
  };
  SpreadsheetControlSC.LoadPrintSetupFields = function (s) {
    var attribs = s.sheet.attribs;
    var areaEle = document.getElementById(s.idPrefix + 'print-area');
    var repeatRowsEle = document.getElementById(s.idPrefix + 'print-repeatrows');
    var repeatColsEle = document.getElementById(s.idPrefix + 'print-repeatcols');
    var orientationEle = document.getElementById(s.idPrefix + 'print-orientation');
    var scaleEle = document.getElementById(s.idPrefix + 'print-scale');
    if (areaEle) areaEle.value = attribs.printarea || '';
    if (repeatRowsEle) repeatRowsEle.value = attribs.printrepeatrows || '';
    if (repeatColsEle) repeatColsEle.value = attribs.printrepeatcols || '';
    if (orientationEle) orientationEle.value = attribs.printorientation || 'portrait';
    if (scaleEle) scaleEle.value = String(attribs.printscale || 100);
  };
  SpreadsheetControlSC.ApplyPrintSetup = function () {
    var s = SocialCalc.GetSpreadsheetControlObject();
    var attribs = s.sheet.attribs;
    var cmds = [];
    var areaEle = document.getElementById(s.idPrefix + 'print-area');
    var repeatRowsEle = document.getElementById(s.idPrefix + 'print-repeatrows');
    var repeatColsEle = document.getElementById(s.idPrefix + 'print-repeatcols');
    var orientationEle = document.getElementById(s.idPrefix + 'print-orientation');
    var scaleEle = document.getElementById(s.idPrefix + 'print-scale');
    var area = areaEle ? areaEle.value.trim() : '';
    var repeatRows = repeatRowsEle ? repeatRowsEle.value.trim() : '';
    var repeatCols = repeatColsEle ? repeatColsEle.value.trim() : '';
    var orientation = orientationEle ? orientationEle.value : 'portrait';
    var scale = scaleEle ? scaleEle.value.trim() - 0 : 100;
    if (area != (attribs.printarea || '')) cmds.push('set sheet printarea ' + area);
    if (repeatRows != (attribs.printrepeatrows || ''))
      cmds.push('set sheet printrepeatrows ' + repeatRows);
    if (repeatCols != (attribs.printrepeatcols || ''))
      cmds.push('set sheet printrepeatcols ' + repeatCols);
    if (orientation != (attribs.printorientation || 'portrait'))
      cmds.push('set sheet printorientation ' + orientation);
    if (scale != (attribs.printscale || 100)) cmds.push('set sheet printscale ' + scale);
    if (cmds.length) {
      s.editor.EditorScheduleSheetCommands(cmds.join('\n'), true, false);
    }
  };
  SpreadsheetControlSC.PreparePrintArea = function (s) {
    var fullgrid = s.editor.fullgrid;
    if (!fullgrid) return;
    var attribs = s.sheet.attribs;
    fullgrid.className = (fullgrid.className || '').replace(/\bsc-print-area\b/g, '').trim();
    fullgrid.className = (fullgrid.className ? fullgrid.className + ' ' : '') + 'sc-print-area';
    var printRange = attribs.printarea ? SocialCalc.ParseRange(attribs.printarea) : null;
    var rows = fullgrid.querySelectorAll('[role="row"]');
    var r;
    for (r = 0; r < rows.length; r++) {
      var rowEle = rows[r];
      var cells = rowEle.querySelectorAll(
        '[role="gridcell"],[role="columnheader"],[role="rowheader"]',
      );
      var c;
      for (c = 0; c < cells.length; c++) {
        var cellEle = cells[c];
        cellEle.className = (cellEle.className || '').replace(/\bsc-print-hide\b/g, '').trim();
        if (!printRange) continue;
        var cellRow = cellEle.getAttribute('aria-rowindex') - 0;
        var cellCol = cellEle.getAttribute('aria-colindex') - 0;
        var outsideRows = cellRow && (cellRow < printRange.cr1.row || cellRow > printRange.cr2.row);
        var outsideCols = cellCol && (cellCol < printRange.cr1.col || cellCol > printRange.cr2.col);
        if (outsideRows || outsideCols) {
          cellEle.className = (cellEle.className ? cellEle.className + ' ' : '') + 'sc-print-hide';
        }
      }
    }
    var repeatRowRange = attribs.printrepeatrows
      ? SocialCalc.ParseRange(
          attribs.printrepeatrows +
            (attribs.printrepeatrows.indexOf(':') < 0 ? ':' + attribs.printrepeatrows : ''),
        )
      : null;
    for (r = 0; r < rows.length; r++) {
      var repeatRowEle = rows[r];
      repeatRowEle.className = (repeatRowEle.className || '')
        .replace(/\bsc-print-repeat-row\b/g, '')
        .trim();
      if (!repeatRowRange) continue;
      var headerRowIndex = repeatRowEle.getAttribute('aria-rowindex') - 0;
      if (headerRowIndex >= repeatRowRange.cr1.row && headerRowIndex <= repeatRowRange.cr2.row) {
        repeatRowEle.className =
          (repeatRowEle.className ? repeatRowEle.className + ' ' : '') + 'sc-print-repeat-row';
      }
    }
    var repeatColRange = attribs.printrepeatcols
      ? SocialCalc.ParseRange(
          attribs.printrepeatcols +
            (attribs.printrepeatcols.indexOf(':') < 0 ? ':' + attribs.printrepeatcols : ''),
        )
      : null;
    var headerCells = fullgrid.querySelectorAll('[role="rowheader"],[role="columnheader"]');
    for (c = 0; c < headerCells.length; c++) {
      var headerCellEle = headerCells[c];
      headerCellEle.className = (headerCellEle.className || '')
        .replace(/\bsc-print-repeat-col\b/g, '')
        .trim();
      if (!repeatColRange) continue;
      var headerColIndex = headerCellEle.getAttribute('aria-colindex') - 0;
      if (headerColIndex >= repeatColRange.cr1.col && headerColIndex <= repeatColRange.cr2.col) {
        headerCellEle.className =
          (headerCellEle.className ? headerCellEle.className + ' ' : '') + 'sc-print-repeat-col';
      }
    }
    var pageStyleId = 'sc-print-page-style';
    var pageStyleEle = document.getElementById(pageStyleId);
    if (!pageStyleEle) {
      pageStyleEle = document.createElement('style');
      pageStyleEle.id = pageStyleId;
      document.head.appendChild(pageStyleEle);
    }
    var pageSize = attribs.printorientation == 'landscape' ? 'landscape' : 'portrait';
    var pageMargin = attribs.printmargins || '0.75in';
    var pageRule = '@page { size: ' + pageSize + '; margin: ' + pageMargin + '; }';
    if (attribs.printscale && attribs.printscale != 100) {
      pageRule += ' .sc-print-area { zoom: ' + attribs.printscale / 100 + '; }';
    }
    pageStyleEle.textContent = pageRule;
  };
  SpreadsheetControlSC.TriggerPrint = function () {
    var s = SocialCalc.GetSpreadsheetControlObject();
    if (!s) return;
    SocialCalc.PreparePrintArea(s);
    if (typeof window !== 'undefined' && typeof window.print === 'function') {
      window.print();
    }
  };
  SpreadsheetControlSC.SpreadsheetControlCreateSpreadsheetSave = function (
    spreadsheet,
    otherparts,
  ) {
    var result;
    var otherpartsstr = '';
    var otherpartsnames = '';
    var partname, extranl;
    if (otherparts) {
      for (partname in otherparts) {
        if (otherparts[partname].charAt(otherparts[partname].length - 1) != '\n') {
          extranl = '\n';
        } else {
          extranl = '';
        }
        otherpartsstr +=
          '--' +
          spreadsheet.multipartBoundary +
          '\nContent-type: text/plain; charset=UTF-8\n\n' +
          otherparts[partname] +
          extranl;
        otherpartsnames += 'part:' + partname + '\n';
      }
    }
    result =
      'socialcalc:version:1.0\n' +
      'MIME-Version: 1.0\nContent-Type: multipart/mixed; boundary=' +
      spreadsheet.multipartBoundary +
      '\n' +
      '--' +
      spreadsheet.multipartBoundary +
      '\nContent-type: text/plain; charset=UTF-8\n\n' +
      '# SocialCalc Spreadsheet Control Save\nversion:1.0\npart:sheet\npart:edit\npart:audit\n' +
      otherpartsnames +
      '--' +
      spreadsheet.multipartBoundary +
      '\nContent-type: text/plain; charset=UTF-8\n\n' +
      spreadsheet.CreateSheetSave() +
      '--' +
      spreadsheet.multipartBoundary +
      '\nContent-type: text/plain; charset=UTF-8\n\n' +
      spreadsheet.editor.SaveEditorSettings() +
      '--' +
      spreadsheet.multipartBoundary +
      '\nContent-type: text/plain; charset=UTF-8\n\n' +
      spreadsheet.sheet.CreateAuditString() +
      otherpartsstr +
      '--' +
      spreadsheet.multipartBoundary +
      '--\n';
    return result;
  };
  SpreadsheetControlSC.SpreadsheetControlDecodeSpreadsheetSave = function (spreadsheet, str) {
    var pos1,
      mpregex,
      searchinfo,
      boundary,
      boundaryregex,
      blanklineregex,
      start,
      ending,
      lines,
      i,
      line,
      p,
      pnum;
    var parts = {};
    var partlist = [];
    pos1 = str.search(/^MIME-Version:\s1\.0/im);
    if (pos1 < 0) return parts;
    mpregex = /^Content-Type:\s*multipart\/mixed;\s*boundary=(\S+)/gim;
    mpregex.lastIndex = pos1;
    searchinfo = mpregex.exec(str);
    if (!searchinfo || mpregex.lastIndex <= 0) return parts;
    boundary = searchinfo[1];
    boundaryregex = new RegExp('^--' + boundary + '(?:\r\n|\n)', 'mg');
    boundaryregex.lastIndex = mpregex.lastIndex;
    searchinfo = boundaryregex.exec(str);
    blanklineregex = /(?:\r\n|\n)(?:\r\n|\n)/gm;
    blanklineregex.lastIndex = boundaryregex.lastIndex;
    searchinfo = blanklineregex.exec(str);
    if (!searchinfo) return parts;
    start = blanklineregex.lastIndex;
    boundaryregex.lastIndex = start;
    searchinfo = boundaryregex.exec(str);
    if (!searchinfo) return parts;
    ending = searchinfo.index;
    lines = str.substring(start, ending).split(/\r\n|\n/);
    for (i = 0; i < lines.length; i++) {
      line = lines[i];
      p = line.split(':');
      switch (p[0]) {
        case 'version':
          break;
        case 'part':
          partlist.push(p[1]);
          break;
      }
    }
    for (pnum = 0; pnum < partlist.length; pnum++) {
      blanklineregex.lastIndex = ending;
      searchinfo = blanklineregex.exec(str);
      if (!searchinfo) return parts;
      start = blanklineregex.lastIndex;
      if (pnum == partlist.length - 1) {
        boundaryregex = new RegExp('^--' + boundary + '--$', 'mg');
      }
      boundaryregex.lastIndex = start;
      searchinfo = boundaryregex.exec(str);
      if (!searchinfo) return parts;
      ending = searchinfo.index;
      parts[partlist[pnum]] = {
        start,
        end: ending,
      };
    }
    return parts;
  };
  SpreadsheetControlSC.SettingsControls = {
    Controls: {},
    CurrentPanel: null,
  };
  SpreadsheetControlSC.SettingsControlSetCurrentPanel = function (panelobj) {
    SpreadsheetControlSC.SettingsControls.CurrentPanel = panelobj;
    SpreadsheetControlSC.SettingsControls.PopupChangeCallback({ panelobj }, '', null);
  };
  SpreadsheetControlSC.SettingsControlInitializePanel = function (panelobj) {
    var ctrlname, ctrl;
    var sc = SocialCalc.SettingsControls;
    for (ctrlname in panelobj) {
      if (ctrlname == 'name') continue;
      ctrl = sc.Controls[panelobj[ctrlname].type];
      if (ctrl && ctrl.Initialize) ctrl.Initialize(panelobj, ctrlname);
    }
  };
  SpreadsheetControlSC.SettingsControlLoadPanel = function (panelobj, attribs) {
    var ctrlname, ctrl;
    var sc = SocialCalc.SettingsControls;
    for (ctrlname in panelobj) {
      if (ctrlname == 'name') continue;
      ctrl = sc.Controls[panelobj[ctrlname].type];
      if (ctrl && ctrl.SetValue)
        ctrl.SetValue(panelobj, ctrlname, attribs[panelobj[ctrlname].setting]);
    }
  };
  SpreadsheetControlSC.SettingsControlUnloadPanel = function (panelobj) {
    var ctrlname, ctrl;
    var sc = SocialCalc.SettingsControls;
    var attribs = {};
    for (ctrlname in panelobj) {
      if (ctrlname == 'name') continue;
      ctrl = sc.Controls[panelobj[ctrlname].type];
      if (ctrl && ctrl.GetValue)
        attribs[panelobj[ctrlname].setting] = ctrl.GetValue(panelobj, ctrlname);
    }
    return attribs;
  };
  SpreadsheetControlSC.SettingsControls.PopupChangeCallback = function (attribs, _id, _value) {
    var sc = SocialCalc.Constants;
    var ele = document.getElementById('sample-text');
    if (!ele || !attribs || !attribs.panelobj) return;
    var idPrefix = SocialCalc.CurrentSpreadsheetControlObject.idPrefix;
    var c = attribs.panelobj.name == 'cell' ? 'c' : '';
    var v, a, parts, str1, str2;
    parts =
      sc.defaultCellLayout.match(/^padding.(\S+) (\S+) (\S+) (\S+).vertical.align.(\S+);$/) || [];
    var cv = {
      color: ['textcolor'],
      backgroundColor: ['bgcolor', '#FFF'],
      fontSize: ['fontsize', sc.defaultCellFontSize],
      fontFamily: ['fontfamily'],
      paddingTop: ['padtop', parts[1]],
      paddingRight: ['padright', parts[2]],
      paddingBottom: ['padbottom', parts[3]],
      paddingLeft: ['padleft', parts[4]],
      verticalAlign: ['alignvert', parts[5]],
    };
    for (a in cv) {
      v = SpreadsheetControlSC.Popup.GetValue(idPrefix + c + cv[a][0]) || cv[a][1] || '';
      ele.style[a] = v;
    }
    if (c == 'c') {
      cv = {
        borderTop: 'cbt',
        borderRight: 'cbr',
        borderBottom: 'cbb',
        borderLeft: 'cbl',
      };
      for (a in cv) {
        v = SpreadsheetControlSC.SettingsControls.BorderSideGetValue(attribs.panelobj, cv[a]);
        ele.style[a] = v ? v.val || '' : '';
      }
      v = SpreadsheetControlSC.Popup.GetValue(idPrefix + 'calignhoriz');
      ele.style.textAlign = v || 'left';
      ele.childNodes[1].style.textAlign = v || 'right';
    } else {
      ele.style.border = '';
      v = SpreadsheetControlSC.Popup.GetValue(idPrefix + 'textalignhoriz');
      ele.style.textAlign = v || 'left';
      v = SpreadsheetControlSC.Popup.GetValue(idPrefix + 'numberalignhoriz');
      ele.childNodes[1].style.textAlign = v || 'right';
    }
    v = SpreadsheetControlSC.Popup.GetValue(idPrefix + c + 'fontlook');
    parts = v ? v.match(/^(\S+) (\S+)$/) || [] : [];
    ele.style.fontStyle = parts[1] || '';
    ele.style.fontWeight = parts[2] || '';
    v = SpreadsheetControlSC.Popup.GetValue(idPrefix + c + 'formatnumber') || 'General';
    str1 = SocialCalc.FormatNumber.formatNumberWithFormat(9.8765, v, '');
    str2 = SocialCalc.FormatNumber.formatNumberWithFormat(-1234.5, v, '');
    if (str2 != '??-???-??&nbsp;??:??:??') {
      str1 += '<br>' + str2;
    }
    ele.childNodes[1].innerHTML = str1;
  };
  SpreadsheetControlSC.SettingsControls.PopupListSetValue = function (panelobj, ctrlname, value) {
    if (!value) {
      alert(ctrlname + ' no value');
      return;
    }
    var sp = SocialCalc.Popup;
    if (!value.def) {
      sp.SetValue(panelobj[ctrlname].id, value.val);
    } else {
      sp.SetValue(panelobj[ctrlname].id, '');
    }
  };
  SpreadsheetControlSC.SettingsControls.PopupListGetValue = function (panelobj, ctrlname) {
    var ctl = panelobj[ctrlname];
    if (!ctl) return null;
    var value = SpreadsheetControlSC.Popup.GetValue(ctl.id);
    if (value) {
      return {
        def: false,
        val: value,
      };
    } else {
      return {
        def: true,
        val: 0,
      };
    }
  };
  SpreadsheetControlSC.SettingsControls.PopupListInitialize = function (panelobj, ctrlname) {
    var i, val, pos, otext;
    var sc = SocialCalc.SettingsControls;
    var initialdata =
      panelobj[ctrlname].initialdata || sc.Controls[panelobj[ctrlname].type].InitialData || '';
    initialdata = SocialCalc.LocalizeSubstrings(initialdata);
    var optionvals = initialdata.split(/\|/);
    var options = [];
    for (i = 0; i < optionvals.length; i++) {
      val = optionvals[i];
      pos = val.indexOf(':');
      otext = val.substring(0, pos);
      if (otext.indexOf('\\') != -1) {
        otext = otext.replace(/\\c/g, ':');
        otext = otext.replace(/\\b/g, '\\');
      }
      otext = SocialCalc.special_chars(otext);
      if (otext == '[custom]') {
        options[i] = {
          o: SocialCalc.Constants.s_PopupListCustom,
          v: val.substring(pos + 1),
          a: { custom: true },
        };
      } else if (otext == '[cancel]') {
        options[i] = {
          o: SocialCalc.Constants.s_PopupListCancel,
          v: '',
          a: { cancel: true },
        };
      } else if (otext == '[break]') {
        options[i] = {
          o: '-----',
          v: '',
          a: { skip: true },
        };
      } else if (otext == '[newcol]') {
        options[i] = {
          o: '',
          v: '',
          a: { newcol: true },
        };
      } else {
        options[i] = {
          o: otext,
          v: val.substring(pos + 1),
        };
      }
    }
    SpreadsheetControlSC.Popup.Create('List', panelobj[ctrlname].id, {});
    SpreadsheetControlSC.Popup.Initialize(panelobj[ctrlname].id, {
      options,
      attribs: {
        changedcallback: SpreadsheetControlSC.SettingsControls.PopupChangeCallback,
        panelobj,
      },
    });
  };
  SpreadsheetControlSC.SettingsControls.PopupListReset = function (_ctrlname) {
    SpreadsheetControlSC.Popup.Reset('List');
  };
  SpreadsheetControlSC.SettingsControls.Controls.PopupList = {
    SetValue: SpreadsheetControlSC.SettingsControls.PopupListSetValue,
    GetValue: SpreadsheetControlSC.SettingsControls.PopupListGetValue,
    Initialize: SpreadsheetControlSC.SettingsControls.PopupListInitialize,
    OnReset: SpreadsheetControlSC.SettingsControls.PopupListReset,
    ChangedCallback: null,
  };
