        spreadsheet.statuslineheight -
        (Number(spreadsheet.statuslineDiv.style.paddingTop.slice(0, -2)) || 0) -
        (Number(spreadsheet.statuslineDiv.style.paddingBottom.slice(0, -2)) || 0) +
        'px';
